export default KPICard;

import React, { useRef, useEffect } from 'react';
import { Bar, Line } from 'react-chartjs-2';
import { formatCurrency, formatNumber } from '../../utils/formatters';
import { Tag, Maximize2, X } from 'lucide-react';
import clsx from 'clsx';
import YearlyPieChart from '../YearlyPieChart';

const DetailsChart = ({
    chartData,
    chartType,
    metric,
    showLabels,
    setShowLabels,
    selectedYear,
    isFullScreen,
    setIsFullScreen,
}) => {
    const fsRef = useRef(null);
    const prevFS = useRef(false);

    // ── Native fullscreen ──────────────────────────────────────────────────
    useEffect(() => {
        const sync = () => setIsFullScreen(!!(document.fullscreenElement || document.webkitFullscreenElement));
        document.addEventListener('fullscreenchange', sync);
        document.addEventListener('webkitfullscreenchange', sync);
        return () => { document.removeEventListener('fullscreenchange', sync); document.removeEventListener('webkitfullscreenchange', sync); };
    }, [setIsFullScreen]);

    useEffect(() => {
        if (prevFS.current === isFullScreen) return;
        prevFS.current = isFullScreen;
        const el = fsRef.current;
        if (!el) return;
        if (isFullScreen) {
            const req = el.requestFullscreen || el.webkitRequestFullscreen;
            if (req) req.call(el).catch(() => setIsFullScreen(false));
        } else {
            const hasFS = document.fullscreenElement || document.webkitFullscreenElement;
            if (hasFS) { const exit = document.exitFullscreen || document.webkitExitFullscreen; if (exit) exit.call(document).catch(() => { }); }
        }
    }, [isFullScreen]);

    // ── Format helpers ───────────────────────────────────────────────
    const fmt = (v) => metric === 'transactions' ? formatNumber(v) : formatCurrency(v);

    // ── Chart options ──────────────────────────────────────────────────
    // NOTE: options is recomputed each render; we add `chartKey` dependency below
    // to force a full chart remount when showLabels changes (ensures plugin sees fresh state).
    const prevShort = selectedYear === '2026' ? "'25" : "'24";

    const options = {
        maintainAspectRatio: false,
        clip: false,                    // allow label pills to render outside chart area
        interaction: { mode: 'index', intersect: false },
        layout: { padding: { top: 48 } },
        plugins: {
            legend: { position: 'bottom', labels: { usePointStyle: true, padding: 16, font: { size: 12 } } },
            tooltip: {
                mode: 'index',
                intersect: false,
                backgroundColor: 'rgba(255,255,255,0.97)',
                titleColor: '#111827',
                bodyColor: '#374151',
                borderColor: 'rgba(0,0,0,0.10)',
                borderWidth: 1,
                padding: 12,
                titleFont: { size: 12, weight: '700', family: 'Lora, serif' },
                bodyFont: { size: 12, family: 'Inter, sans-serif' },
                callbacks: {
                    label: (ctx) => {
                        const ds = ctx.dataset;
                        const val = ctx.parsed?.y;
                        if (val == null) return ` ${ds.label}: —`;
                        const fmtVal = fmt(Math.round(val));
                        const isPrimary = !ds.borderDash?.length && !ds.label?.includes('Budget');
                        if (!isPrimary) return ` ${ds.label}: ${fmtVal}`;

                        const datasets = ctx.chart.data.datasets;
                        const idx = ctx.dataIndex;
                        const unitBase = ds.label.replace(/\s'\d{2}$/, '');
                        const dsPrev = datasets.find(d => d.borderDash?.length > 0 && d.label?.startsWith(unitBase));
                        const dsBud = datasets.find(d => d.label?.includes('Budget') && d.label?.startsWith(unitBase));

                        const lines = [` ${ds.label}: ${fmtVal}`];
                        if (dsPrev?.data[idx]) {
                            const pct = Math.round(((val - dsPrev.data[idx]) / dsPrev.data[idx]) * 100);
                            lines.push(`   ${pct >= 0 ? '↑' : '↓'} ${pct >= 0 ? '+' : ''}${pct}% vs ${prevShort}`);
                        }
                        if (dsBud?.data[idx]) {
                            const pct = Math.round(((val - dsBud.data[idx]) / dsBud.data[idx]) * 100);
                            lines.push(`   ${pct >= 0 ? '↑' : '↓'} ${pct >= 0 ? '+' : ''}${pct}% vs Budget`);
                        }
                        return lines;
                    },
                },
            },
            datalabels: {
                // display is a DIRECT boolean — no closure, no caching issues
                // Comparison/budget datasets opt out individually via dataset.datalabels.display = false
                display: showLabels,
                anchor: 'end',
                align: 'end',
                offset: 6,
                clip: false,
                clamp: true,
                backgroundColor: 'rgba(255,255,255,0.93)',
                borderColor: 'rgba(0,0,0,0.10)',
                borderWidth: 1,
                borderRadius: 6,
                padding: { top: 3, bottom: 3, left: 7, right: 7 },
                color: '#111827',
                font: { size: 11, weight: '700', family: 'Inter, sans-serif' },
                formatter: (value) => value ? fmt(Math.round(value)) : null,
            },
        },
        scales: {
            x: { grid: { display: false }, ticks: { maxRotation: 40, font: { size: 11 } } },
            y: { grid: { color: 'rgba(0,0,0,0.05)' }, ticks: { callback: (v) => fmt(Math.round(v)), font: { size: 11 } } },
        },
    };

    // ── Header buttons ──────────────────────────────────────────────────
    const HeaderButtons = ({ extra } = {}) => (
        <div className="flex items-center gap-2">
            {extra}
            <button
                onClick={() => setShowLabels(prev => !prev)}
                className={clsx(
                    'flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-lg border transition-all',
                    showLabels
                        ? 'bg-primary text-white border-primary shadow-sm'
                        : 'border-gray-200 text-gray-500 hover:border-gray-400 hover:text-gray-700 bg-white'
                )}
            >
                <Tag className="w-3.5 h-3.5" /> Labels
            </button>
            <button
                onClick={() => setIsFullScreen(true)}
                className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-lg border border-gray-200 text-gray-500 hover:border-gray-400 hover:text-gray-700 bg-white transition-all"
            >
                <Maximize2 className="w-3.5 h-3.5" /> Fullscreen
            </button>
        </div>
    );

    if (!chartData || !chartData.datasets?.length) {
        return (
            <div>
                <div className="flex justify-end mb-3"><HeaderButtons /></div>
                <div className="flex items-center justify-center h-64 text-gray-400 italic text-sm">
                    Select at least one business unit.
                </div>
            </div>
        );
    }

    const ChartComponent = chartType === 'line' ? Line : Bar;
    // key forces full remount when showLabels toggles — guarantees plugin sees fresh boolean
    const chartKey = `${chartType}-${metric}-${showLabels}`;

    if (chartType === 'donut') {
        const units = Object.keys(chartData.unitTotals || {}).filter(u => u !== 'All Groups');
        const dataVals = units.map(u => chartData.unitTotals[u] || 0);

        return (
            <div ref={fsRef} className="relative w-full bg-white">
                {isFullScreen && (
                    <div className="absolute inset-0 bg-white flex flex-col" style={{ zIndex: 10 }}>
                        <div className="flex justify-between items-center p-4 flex-shrink-0 border-b border-gray-100">
                            <span className="text-sm font-semibold text-gray-600">Detailed Sales Analysis - Contribution</span>
                            <HeaderButtons extra={
                                <button
                                    onClick={() => setIsFullScreen(false)}
                                    className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 hover:bg-gray-200 rounded-lg text-xs font-semibold text-gray-700 transition-colors"
                                >
                                    <X className="w-3.5 h-3.5" /> Exit
                                </button>
                            } />
                        </div>
                        <div className="flex-1 px-6 pb-6 min-h-0 flex items-center justify-center">
                            <YearlyPieChart labels={units} dataValues={dataVals} />
                        </div>
                    </div>
                )}
                {!isFullScreen && (
                    <>
                        <div className="flex justify-end mb-3"><HeaderButtons /></div>
                        <div className="h-[400px] flex justify-center">
                            <YearlyPieChart labels={units} dataValues={dataVals} />
                        </div>
                    </>
                )}
            </div>
        );
    }

    return (
        <div ref={fsRef} className="relative w-full bg-white">
            {isFullScreen && (
                <div className="absolute inset-0 bg-white flex flex-col" style={{ zIndex: 10 }}>
                    <div className="flex justify-between items-center p-4 flex-shrink-0 border-b border-gray-100">
                        <span className="text-sm font-semibold text-gray-600">Detailed Sales Analysis</span>
                        <HeaderButtons extra={
                            <button
                                onClick={() => setIsFullScreen(false)}
                                className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 hover:bg-gray-200 rounded-lg text-xs font-semibold text-gray-700 transition-colors"
                            >
                                <X className="w-3.5 h-3.5" /> Exit
                            </button>
                        } />
                    </div>
                    <div className="flex-1 px-6 pb-6 min-h-0">
                        <ChartComponent key={chartKey} data={chartData} options={options} />
                    </div>
                </div>
            )}

            {!isFullScreen && (
                <>
                    <div className="flex justify-end mb-3"><HeaderButtons /></div>
                    <div className="h-[400px]">
                        <ChartComponent key={chartKey} data={chartData} options={options} />
                    </div>
                </>
            )}
        </div>
    );
};

export default DetailsChart;

import React from 'react';
import { MONTHS, BUSINESS_UNITS, WEEKLY_LABELS_2025, WEEKLY_LABELS_2026 } from '../../services/dataService';
import clsx from 'clsx';
import DateRangePicker from '../DateRangePicker';
import SegmentedControl from '../ui/SegmentedControl';

const VIEW_OPTIONS = [
    { value: 'monthly', label: 'Monthly' },
    { value: 'weekly', label: 'Weekly' },
    { value: 'daily', label: 'Daily' },
    { value: 'yearly', label: 'Yearly' },
];

const METRIC_OPTIONS = [
    { value: 'sales', label: 'Sales €' },
    { value: 'transactions', label: 'Volume' },
    { value: 'spend', label: 'Avg Spend' },
];

const CHART_OPTIONS = [
    { value: 'bar', label: 'Bar' },
    { value: 'line', label: 'Line' },
    { value: 'donut', label: 'Donut' },
];

const PRESET_LABELS = [
    { value: 'q1', label: 'Q1' },
    { value: 'q2', label: 'Q2' },
    { value: 'q3', label: 'Q3' },
    { value: 'q4', label: 'Q4' },
    { value: 'summer', label: 'Summer' },
    { value: 'ytd', label: 'YTD' },
];

const DetailsFilters = ({
    selectedYear, setSelectedYear,
    selectedUnits, toggleUnit,
    metric, setMetric,
    viewType, setViewType,
    chartType, setChartType,
    startPeriod, setStartPeriod,
    endPeriod, setEndPeriod,
    dailyStart, dailyEnd, onDailyRangeChange,
    compare24, setCompare24,
    compareBudget, setCompareBudget,
    includeVat, setIncludeVat,
    handlePredefinedPeriod,
}) => {
    const weeklyLabels = selectedYear === '2026' ? WEEKLY_LABELS_2026 : WEEKLY_LABELS_2025;
    const isDaily = viewType === 'daily';
    const isYearly = viewType === 'yearly';
    const showPeriod = !isDaily && !isYearly;

    const PillToggle = ({ checked, onChange, label, disabled }) => (
        <button
            onClick={() => !disabled && onChange(!checked)}
            className={clsx(
                'px-3 py-1.5 text-xs font-semibold rounded-full border transition-all duration-200 select-none',
                disabled
                    ? 'border-gray-200 text-gray-300 cursor-not-allowed'
                    : checked
                        ? 'bg-primary text-white border-primary shadow-sm'
                        : 'border-gray-300 text-gray-500 hover:border-accent hover:text-accent bg-white'
            )}
            disabled={disabled}
        >
            {checked ? '✓ ' : ''}{label}
        </button>
    );

    return (
        // No overflow-hidden — DateRangePicker calendar must not be clipped
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm mb-6">

            {/* Row 1: Controls */}
            <div className="flex flex-wrap items-center gap-3 px-5 py-4 border-b border-gray-100">
                <SegmentedControl
                    options={[{ value: '2025', label: '2025' }, { value: '2026', label: '2026' }]}
                    value={selectedYear}
                    onChange={setSelectedYear}
                    disabled={isDaily}
                />
                <div className="w-px h-7 bg-gray-200" />
                <SegmentedControl options={VIEW_OPTIONS} value={viewType} onChange={setViewType} />
                <div className="w-px h-7 bg-gray-200" />
                <SegmentedControl
                    options={METRIC_OPTIONS.map(o => ({ ...o, disabled: isDaily && o.value !== 'sales' }))}
                    value={metric}
                    onChange={setMetric}
                    disabled={isDaily}
                />
                <div className="w-px h-7 bg-gray-200" />
                <SegmentedControl options={CHART_OPTIONS} value={chartType} onChange={setChartType} />
            </div>

            {/* Row 2: Business Unit Chips */}
            <div className="px-5 py-3 border-b border-gray-100">
                <p className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mb-2">Business Units</p>
                <div className="flex flex-wrap gap-2">
                    <button
                        onClick={() => toggleUnit('All Groups')}
                        className={clsx('bu-chip font-semibold', selectedUnits.includes('All Groups') && 'active')}
                    >All Groups</button>
                    {BUSINESS_UNITS.map(u => (
                        <button key={u} onClick={() => toggleUnit(u)} className={clsx('bu-chip', selectedUnits.includes(u) && 'active')}>{u}</button>
                    ))}
                </div>
            </div>

            {/* Row 3: Comparison Toggles */}
            <div className="flex flex-wrap items-center gap-3 px-5 py-3 border-b border-gray-100 bg-gray-50/50">
                <span className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mr-1">Compare:</span>
                <PillToggle checked={compare24} onChange={setCompare24} label={`vs '${selectedYear === '2026' ? '25' : '24'}`} disabled={isYearly} />
                <PillToggle checked={includeVat} onChange={setIncludeVat} label="Inc. VAT" />
                <PillToggle checked={compareBudget} onChange={setCompareBudget} label="vs Budget" disabled={isYearly || metric !== 'sales'} />
            </div>

            {/* Row 4a: Period Selector */}
            {showPeriod && (
                <div className="flex flex-wrap items-center gap-3 px-5 py-3">
                    <span className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider mr-1">Period:</span>
                    {PRESET_LABELS.map(p => (
                        <button
                            key={p.value}
                            onClick={() => handlePredefinedPeriod({ target: { value: p.value } })}
                            className="px-3 py-1 text-xs font-medium border border-gray-300 rounded-full text-gray-600 hover:border-accent hover:text-accent hover:bg-accent/5 transition-all"
                        >{p.label}</button>
                    ))}
                    <div className="w-px h-5 bg-gray-200" />
                    <div className="flex items-center gap-2 text-sm">
                        <span className="text-gray-400 text-xs">From</span>
                        <select value={startPeriod} onChange={e => setStartPeriod(Number(e.target.value))}
                            className="border border-gray-200 rounded-lg px-2 py-1.5 text-sm text-gray-700 focus:ring-1 focus:ring-accent focus:outline-none">
                            {(viewType === 'monthly' ? MONTHS : weeklyLabels).map((lbl, i) => (
                                <option key={i} value={i}>{lbl}</option>
                            ))}
                        </select>
                        <span className="text-gray-400">→</span>
                        <select value={endPeriod} onChange={e => setEndPeriod(Number(e.target.value))}
                            className="border border-gray-200 rounded-lg px-2 py-1.5 text-sm text-gray-700 focus:ring-1 focus:ring-accent focus:outline-none">
                            {(viewType === 'monthly' ? MONTHS : weeklyLabels).map((lbl, i) => (
                                <option key={i} value={i}>{lbl}</option>
                            ))}
                        </select>
                    </div>
                </div>
            )}

            {/* Row 4b: Daily DateRangePicker */}
            {isDaily && (
                <div className="flex items-center gap-3 px-5 py-3">
                    <span className="text-[11px] font-semibold text-gray-400 uppercase tracking-wider">Date Range:</span>
                    <DateRangePicker
                        startDate={dailyStart}
                        endDate={dailyEnd}
                        onChange={(start, end) => onDailyRangeChange(start, end)}
                    />
                </div>
            )}
        </div>
    );
};

export default DetailsFilters;
